function TodoList({ todos, onDelete, onToggle }) {
  const handleDelete = useCallback(
    (id) => onDelete(id),
    [onDelete]
  );
  const handleToggle = useCallback(
    (id) => onToggle(id),
    [onToggle]
  );

  return (
    <ul>
      {todos.map(todo => (
        <li key={todo.id}>
          <span>{todo.text}</span>
          <button onClick={() => handleToggle(todo.id)}>Toggle</button>
          <button onClick={() => handleDelete(todo.id)}>Delete</button>
        </li>
      ))}
    </ul>
  );
}
